// =======================================
// GET STORED FLEET DATA
// =======================================

let fleet = flow.get("fleet") || {}

let d = msg.payload

if (!d || !d.truck) return null

// =======================================
// STORE / UPDATE TRUCK DATA
// =======================================

fleet[d.truck] = d
flow.set("fleet", fleet)

let trucks = Object.values(fleet)

// =======================================
// VARIABLES
// =======================================

let totalSpeed = 0
let totalTemp = 0

let overspeed = 0
let highTemp = 0
let outsideZone = 0

let normal = 0
let warning = 0

let healthy = 0
let tempWarning = 0
let critical = 0

let problemTrucks = []

// =======================================
// PROCESS TRUCK DATA
// =======================================

for (let t of trucks) {

    let speed = Number(t.speed || 0)

    let temp = Number(
        t.temp || (t.rpm ? t.rpm / 50 : 90)
    )

    let distance = Number(t.distance_km || 0)

    totalSpeed += speed
    totalTemp += temp

    // SPEED DISTRIBUTION
    if (speed > 100) {
        overspeed++
        problemTrucks.push(`🚨 ${t.truck} → OVER_SPEED (${speed} km/h)`)
    }
    else if (speed >= 80) {
        warning++
    }
    else {
        normal++
    }

    // ENGINE HEALTH
    if (temp > 110) {
        highTemp++
        critical++
        problemTrucks.push(`🔥 ${t.truck} → TEMP_HIGH (${temp}°C)`)
    }
    else if (temp >= 90) {
        tempWarning++
    }
    else {
        healthy++
    }

    // GEOFENCE ALERT
    if (distance > 100) {
        outsideZone++
        problemTrucks.push(`📍 ${t.truck} → OUTSIDE_ZONE (${distance} km)`)
    }
}

// =======================================
// CALCULATE AVERAGES
// =======================================

let avgSpeed = trucks.length ? Math.round(totalSpeed / trucks.length) : 0
let avgTemp = trucks.length ? Math.round(totalTemp / trucks.length) : 0

// =======================================
// LIMIT PROBLEM LIST
// =======================================

problemTrucks = problemTrucks.slice(0, 5)

let problemMessage =
    problemTrucks.length > 0
        ? problemTrucks.join("<br>")
        : "✅ No Critical Trucks"

// =======================================
// OUTPUTS
// =======================================

return [

    // OUTPUT 1 → MAP
    {
        payload: {
            name: d.truck,
            lat: Number(d.lat),
            lon: Number(d.lon),
            icon: "truck",
            layer: "fleet"
        }
    },

    // OUTPUT 2 → TEMPERATURE GAUGE
    {
        payload: avgTemp
    },

    // OUTPUT 3 → SPEED GAUGE
    {
        payload: avgSpeed
    },

    // OUTPUT 4 → FLEET SUMMARY
    {
        payload:
            "Total Trucks: " + trucks.length +
            "<br>Overspeed: " + overspeed +
            "<br>High Temp: " + highTemp +
            "<br>Outside Zone: " + outsideZone
    },

    // OUTPUT 5 → FLEET TABLE
    {
        payload: trucks
    },

    // OUTPUT 6 → SPEED DISTRIBUTION CHART
    {
        payload: [
            { label: "Normal", value: normal },
            { label: "Warning", value: warning },
            { label: "Overspeed", value: overspeed }
        ]
    },

    // OUTPUT 7 → TOP PROBLEM TRUCKS
    {
        payload: problemMessage
    },

    // OUTPUT 8 → ENGINE HEALTH DISTRIBUTION  (FIXED FORMAT)
    [
        { topic: "Healthy", payload: healthy },
        { topic: "Temp Warning", payload: tempWarning },
        { topic: "Critical", payload: critical }
    ]

]

let fleet = flow.get("fleet") || {};
let trucks = Object.values(fleet);

// 1. We remove the reset command so the chart doesn't flash blank.

for (let t of trucks) {
    // 2. The chart finds the existing bar for this truck and smoothly 
    // updates its height to the new speed.
    node.send({
        topic: t.truck,
        payload: t.speed
    });
}

return null;

let fleet = flow.get("fleet") || {}

let trucks = Object.values(fleet)

let problems = []

for (let t of trucks) {

    let speed = Number(t.speed || 0)
    let temp = Number(t.temp || 0)

    if (speed > 80) {
        problems.push(`🚨 ${t.truck} → OVER_SPEED (${speed} km/h)`)
    }

    if (temp > 110) {
        problems.push(`🔥 ${t.truck} → TEMP_HIGH (${temp}°C)`)
    }

    if (t.alert && t.alert.includes("GEO_OUT")) {
        problems.push(`📍 ${t.truck} → OUTSIDE_ZONE`)
    }
}

// show max 5 trucks to keep dashboard clean
problems = problems.slice(0, 4)

msg.payload = problems.join("<br>") || "✅ No Critical Trucks"

return msg
